"use client";
/* ================================================================
   Sidebar — Collapsible navigation with permission-based menu
   Fetches menu from /menu-items/me API and renders hierarchy
   ================================================================ */
import { useState, useEffect } from "react";
import Link from "next/link";
import { usePathname } from "next/navigation";
import { useSidebarStore } from "@/store/sidebarStore";

interface MenuChild {
  name: string;
  route: string;
  icon: string;
}

interface MenuItemDef {
  name: string;
  code: string;
  route: string;
  icon: string;
  children?: MenuChild[];
}

// ─── Static menu for Phase 0/1 (replaced by API in Phase 2) ──
const STATIC_MENU: { section: string; items: MenuItemDef[] }[] = [
  {
    section: "MAIN",
    items: [
      { name: "Dashboard", code: "dashboard", route: "/dashboard", icon: "fa-gauge-high" },
    ],
  },
  {
    section: "USER MANAGEMENT",
    items: [
      { name: "Users", code: "users", route: "/users", icon: "fa-users",
        children: [
          { name: "All Users", route: "/users", icon: "fa-list" },
          { name: "Create User", route: "/users/create", icon: "fa-user-plus" },
        ],
      },
    ],
  },
  {
    section: "ACCESS CONTROL",
    items: [
      { name: "Roles", code: "roles", route: "/roles", icon: "fa-shield-halved" },
      { name: "Permissions", code: "permissions", route: "/permissions", icon: "fa-key" },
      { name: "Role Permissions", code: "role-permissions", route: "/role-permissions", icon: "fa-user-lock" },
      { name: "User Assignments", code: "user-role-assignments", route: "/user-role-assignments", icon: "fa-user-tag" },
    ],
  },
  {
    section: "SYSTEM",
    items: [
      { name: "Menu Items", code: "menu-items", route: "/menu-items", icon: "fa-bars" },
      { name: "Audit Log", code: "audit-log", route: "/audit-log", icon: "fa-clock-rotate-left" },
      { name: "Settings", code: "settings", route: "/settings", icon: "fa-gear" },
    ],
  },
];

export default function Sidebar() {
  const pathname = usePathname();
  const { isCollapsed, isMobileOpen, expandedMenus, toggleExpandedMenu, setMobileOpen } =
    useSidebarStore();
  const [mounted, setMounted] = useState(false);

  useEffect(() => setMounted(true), []);

  if (!mounted) return null;

  const isActive = (route: string) => {
    if (route === "/dashboard") return pathname === "/dashboard";
    return pathname.startsWith(route);
  };

  const handleItemClick = (item: MenuItemDef) => {
    if (item.children && item.children.length > 0) {
      toggleExpandedMenu(item.code);
    }
    // Close mobile sidebar on navigation
    if (isMobileOpen) setMobileOpen(false);
  };

  return (
    <>
      {/* Mobile overlay */}
      {isMobileOpen && (
        <div
          className="gum-sidebar-overlay"
          onClick={() => setMobileOpen(false)}
          style={{
            position: "fixed",
            inset: 0,
            background: "rgba(0,0,0,0.4)",
            zIndex: 1029,
          }}
        />
      )}

      <aside
        className={`gum-sidebar ${isCollapsed ? "collapsed" : ""} ${isMobileOpen ? "mobile-open" : ""}`}
      >
        {/* ─── Brand ──────────────────────────────────────── */}
        <div className="gum-sidebar__brand">
          <div className="gum-sidebar__brand-logo">G</div>
          {!isCollapsed && (
            <span className="gum-sidebar__brand-text">GrowUpMore</span>
          )}
        </div>

        {/* ─── Navigation ─────────────────────────────────── */}
        <nav className="gum-sidebar__nav">
          {STATIC_MENU.map((section) => (
            <div key={section.section}>
              {!isCollapsed && (
                <div className="gum-sidebar__section-title">
                  {section.section}
                </div>
              )}

              {section.items.map((item) => {
                const hasChildren = item.children && item.children.length > 0;
                const isExpanded = expandedMenus.includes(item.code);
                const itemActive = isActive(item.route);

                return (
                  <div key={item.code}>
                    {hasChildren ? (
                      <div
                        className={`gum-sidebar__menu-item ${itemActive ? "active" : ""} ${isExpanded ? "expanded" : ""}`}
                        onClick={() => handleItemClick(item)}
                      >
                        <i className={`fa-solid ${item.icon} gum-sidebar__menu-icon`} />
                        {!isCollapsed && (
                          <>
                            <span className="gum-sidebar__menu-text">
                              {item.name}
                            </span>
                            <i className="fa-solid fa-chevron-right gum-sidebar__menu-arrow" />
                          </>
                        )}
                      </div>
                    ) : (
                      <Link
                        href={item.route}
                        className={`gum-sidebar__menu-item ${itemActive ? "active" : ""}`}
                        onClick={() => {
                          if (isMobileOpen) setMobileOpen(false);
                        }}
                      >
                        <i className={`fa-solid ${item.icon} gum-sidebar__menu-icon`} />
                        {!isCollapsed && (
                          <span className="gum-sidebar__menu-text">
                            {item.name}
                          </span>
                        )}
                      </Link>
                    )}

                    {/* Submenu */}
                    {hasChildren && !isCollapsed && (
                      <div
                        className="gum-sidebar__submenu"
                        style={{
                          maxHeight: isExpanded
                            ? `${(item.children?.length || 0) * 42}px`
                            : "0",
                        }}
                      >
                        {item.children?.map((child) => (
                          <Link
                            key={child.route}
                            href={child.route}
                            className={`gum-sidebar__menu-item ${pathname === child.route ? "active" : ""}`}
                            onClick={() => {
                              if (isMobileOpen) setMobileOpen(false);
                            }}
                          >
                            <i className={`fa-solid ${child.icon} gum-sidebar__menu-icon`} />
                            <span className="gum-sidebar__menu-text">
                              {child.name}
                            </span>
                          </Link>
                        ))}
                      </div>
                    )}
                  </div>
                );
              })}
            </div>
          ))}
        </nav>

        {/* ─── Sidebar Footer ─────────────────────────────── */}
        {!isCollapsed && (
          <div className="gum-sidebar__footer">
            <small style={{ color: "var(--gum-text-muted)", fontSize: 11 }}>
              GrowUpMore v1.0.0
            </small>
          </div>
        )}
      </aside>
    </>
  );
}
