"use client";
/* ================================================================
   Topbar — App bar with breadcrumbs, search, theme toggle, profile
   ================================================================ */
import { useTheme } from "next-themes";
import { usePathname } from "next/navigation";
import { useState, useEffect } from "react";
import { useSidebarStore } from "@/store/sidebarStore";
import { useAuthStore } from "@/store/authStore";

// ─── Breadcrumb mapping ──────────────────────────────────────
const BREADCRUMB_MAP: Record<string, string> = {
  dashboard: "Dashboard",
  users: "Users",
  create: "Create",
  edit: "Edit",
  roles: "Roles",
  permissions: "Permissions",
  "role-permissions": "Role Permissions",
  "user-role-assignments": "User Assignments",
  "menu-items": "Menu Items",
  "audit-log": "Audit Log",
  settings: "Settings",
  profile: "Profile",
};

export default function Topbar() {
  const { theme, setTheme } = useTheme();
  const pathname = usePathname();
  const { toggleCollapse, toggleMobile } = useSidebarStore();
  const { user } = useAuthStore();
  const [mounted, setMounted] = useState(false);
  const [showProfileMenu, setShowProfileMenu] = useState(false);

  useEffect(() => setMounted(true), []);

  // ─── Generate breadcrumbs from pathname ─────────────────────
  const segments = pathname.split("/").filter(Boolean);
  const breadcrumbs = segments.map((seg, i) => ({
    label: BREADCRUMB_MAP[seg] || seg.charAt(0).toUpperCase() + seg.slice(1),
    path: "/" + segments.slice(0, i + 1).join("/"),
    isLast: i === segments.length - 1,
  }));

  const toggleTheme = () => {
    setTheme(theme === "dark" ? "light" : "dark");
  };

  const userInitials = user
    ? `${user.firstName.charAt(0)}${user.lastName.charAt(0)}`
    : "SA";

  const userName = user
    ? `${user.firstName} ${user.lastName}`
    : "Super Admin";

  if (!mounted) return <div className="gum-topbar" />;

  return (
    <header className="gum-topbar">
      {/* ─── Toggle Sidebar ─────────────────────────────── */}
      <button
        className="gum-topbar__toggle d-none d-md-flex"
        onClick={toggleCollapse}
        title="Toggle sidebar"
      >
        <i className="fa-solid fa-bars" />
      </button>

      <button
        className="gum-topbar__toggle d-md-none"
        onClick={toggleMobile}
        title="Open menu"
      >
        <i className="fa-solid fa-bars" />
      </button>

      {/* ─── Breadcrumbs ────────────────────────────────── */}
      <div className="gum-topbar__breadcrumb">
        <a href="/dashboard">
          <i className="fa-solid fa-house" style={{ fontSize: 13 }} />
        </a>
        {breadcrumbs.map((crumb) => (
          <span key={crumb.path}>
            <span className="separator">/</span>
            {crumb.isLast ? (
              <span className="current">{crumb.label}</span>
            ) : (
              <a href={crumb.path}>{crumb.label}</a>
            )}
          </span>
        ))}
      </div>

      {/* ─── Actions ────────────────────────────────────── */}
      <div className="gum-topbar__actions">
        {/* Search */}
        <button className="gum-topbar__action-btn" title="Search">
          <i className="fa-solid fa-magnifying-glass" />
        </button>

        {/* Notifications */}
        <button className="gum-topbar__action-btn" title="Notifications">
          <i className="fa-solid fa-bell" />
          <span className="gum-topbar__badge" />
        </button>

        {/* Theme Toggle */}
        <button
          className="gum-topbar__action-btn"
          onClick={toggleTheme}
          title={`Switch to ${theme === "dark" ? "light" : "dark"} mode`}
        >
          <i className={`fa-solid ${theme === "dark" ? "fa-sun" : "fa-moon"}`} />
        </button>

        {/* Profile */}
        <div style={{ position: "relative" }}>
          <button
            className="gum-topbar__profile"
            onClick={() => setShowProfileMenu(!showProfileMenu)}
          >
            <div className="gum-topbar__avatar">{userInitials}</div>
            <div className="gum-topbar__user-info">
              <div className="gum-topbar__user-name">{userName}</div>
              <div className="gum-topbar__user-role">Administrator</div>
            </div>
            <i
              className="fa-solid fa-chevron-down"
              style={{ fontSize: 10, color: "var(--gum-text-muted)" }}
            />
          </button>

          {/* Profile Dropdown */}
          {showProfileMenu && (
            <div
              className="gum-card"
              style={{
                position: "absolute",
                right: 0,
                top: "100%",
                marginTop: 8,
                width: 200,
                padding: "8px 0",
                zIndex: 1050,
                boxShadow: "0 4px 20px rgba(0,0,0,0.15)",
              }}
            >
              <a
                href="/users/profile"
                className="gum-sidebar__menu-item"
                style={{ padding: "10px 16px", borderLeft: "none" }}
              >
                <i className="fa-solid fa-user gum-sidebar__menu-icon" />
                <span>My Profile</span>
              </a>
              <a
                href="/settings"
                className="gum-sidebar__menu-item"
                style={{ padding: "10px 16px", borderLeft: "none" }}
              >
                <i className="fa-solid fa-gear gum-sidebar__menu-icon" />
                <span>Settings</span>
              </a>
              <hr style={{ margin: "4px 0", borderColor: "var(--gum-border)" }} />
              <button
                className="gum-sidebar__menu-item"
                style={{
                  padding: "10px 16px",
                  borderLeft: "none",
                  width: "100%",
                  background: "none",
                  border: "none",
                  color: "#DC3545",
                }}
                onClick={() => {
                  useAuthStore.getState().logout();
                  window.location.href = "/login";
                }}
              >
                <i className="fa-solid fa-right-from-bracket gum-sidebar__menu-icon" style={{ color: "#DC3545" }} />
                <span>Logout</span>
              </button>
            </div>
          )}
        </div>
      </div>
    </header>
  );
}
